# React Patterns for Solana dApps

Building Solana frontends requires handling asynchronous blockchain operations gracefully. Let's explore essential React patterns for production-ready dApps.

## Loading States

Blockchain operations are async and can take seconds. Always show loading feedback:

```typescript
function BalanceDisplay() {
  const { publicKey } = useWallet();
  const { connection } = useConnection();
  const [balance, setBalance] = useState<number | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!publicKey) {
      setBalance(null);
      setLoading(false);
      return;
    }

    setLoading(true);
    connection.getBalance(publicKey)
      .then(lamports => setBalance(lamports / LAMPORTS_PER_SOL))
      .catch(err => console.error(err))
      .finally(() => setLoading(false));
  }, [publicKey, connection]);

  if (loading) return <Spinner />;
  if (!publicKey) return <p>Connect your wallet</p>;

  return <p>Balance: {balance?.toFixed(4)} SOL</p>;
}
```

## Error Handling

Network errors, rejected transactions, and insufficient funds are common. Handle them explicitly:

```typescript
function TransferForm() {
  const [error, setError] = useState<string | null>(null);
  const [sending, setSending] = useState(false);

  async function handleTransfer() {
    setError(null);
    setSending(true);

    try {
      const signature = await sendTransaction(transaction, connection);
      await connection.confirmTransaction(signature);
      toast.success(`Transfer successful! ${signature}`);
    } catch (err) {
      if (err instanceof Error) {
        if (err.message.includes('insufficient')) {
          setError('Insufficient SOL balance for this transaction');
        } else if (err.message.includes('rejected')) {
          setError('Transaction rejected by wallet');
        } else {
          setError('Transaction failed. Please try again.');
        }
      }
    } finally {
      setSending(false);
    }
  }

  return (
    <div>
      <button onClick={handleTransfer} disabled={sending}>
        {sending ? 'Sending...' : 'Send SOL'}
      </button>
      {error && <ErrorAlert>{error}</ErrorAlert>}
    </div>
  );
}
```

## Optimistic Updates

Update UI immediately while the transaction confirms in the background:

```typescript
function LikeButton({ postId }: { postId: string }) {
  const [likes, setLikes] = useState(42);
  const [hasLiked, setHasLiked] = useState(false);

  async function handleLike() {
    // Optimistic update
    setLikes(prev => prev + 1);
    setHasLiked(true);

    try {
      // Send transaction
      const signature = await sendLikeTransaction(postId);
      await connection.confirmTransaction(signature);
    } catch (err) {
      // Revert on error
      setLikes(prev => prev - 1);
      setHasLiked(false);
      toast.error('Failed to like post');
    }
  }

  return (
    <button onClick={handleLike} disabled={hasLiked}>
      {hasLiked ? 'Liked!' : 'Like'} ({likes})
    </button>
  );
}
```

## Data Fetching with React Query

`@tanstack/react-query` is perfect for caching blockchain data:

```typescript
import { useQuery } from '@tanstack/react-query';

function useWalletBalance(publicKey: PublicKey | null) {
  const { connection } = useConnection();

  return useQuery({
    queryKey: ['balance', publicKey?.toBase58()],
    queryFn: async () => {
      if (!publicKey) return null;
      const lamports = await connection.getBalance(publicKey);
      return lamports / LAMPORTS_PER_SOL;
    },
    enabled: !!publicKey,
    staleTime: 30_000, // Consider fresh for 30s
    refetchInterval: 60_000, // Auto-refresh every 60s
  });
}

// Usage
function BalanceCard() {
  const { publicKey } = useWallet();
  const { data: balance, isLoading, error } = useWalletBalance(publicKey);

  if (isLoading) return <Skeleton />;
  if (error) return <ErrorState />;

  return <p>{balance?.toFixed(4)} SOL</p>;
}
```

## Subscription Pattern for Real-Time Updates

Use WebSocket subscriptions for instant updates:

```typescript
function useAccountSubscription(publicKey: PublicKey | null) {
  const { connection } = useConnection();
  const [accountInfo, setAccountInfo] = useState<AccountInfo<Buffer> | null>(null);

  useEffect(() => {
    if (!publicKey) return;

    const subscriptionId = connection.onAccountChange(
      publicKey,
      (updatedAccountInfo) => {
        setAccountInfo(updatedAccountInfo);
      },
      'confirmed'
    );

    // Cleanup on unmount
    return () => {
      connection.removeAccountChangeListener(subscriptionId);
    };
  }, [publicKey, connection]);

  return accountInfo;
}
```

## Debouncing User Input

Validate addresses without overwhelming the RPC:

```typescript
import { useDebouncedValue } from '@/hooks/useDebouncedValue';

function RecipientInput() {
  const [address, setAddress] = useState('');
  const debouncedAddress = useDebouncedValue(address, 500);
  const [isValid, setIsValid] = useState<boolean | null>(null);

  useEffect(() => {
    if (!debouncedAddress) {
      setIsValid(null);
      return;
    }

    try {
      new PublicKey(debouncedAddress);
      setIsValid(true);
    } catch {
      setIsValid(false);
    }
  }, [debouncedAddress]);

  return (
    <div>
      <input
        value={address}
        onChange={(e) => setAddress(e.target.value)}
        placeholder="Recipient address"
      />
      {isValid === false && <Error>Invalid Solana address</Error>}
      {isValid === true && <Success>Valid address</Success>}
    </div>
  );
}
```

## Best Practices Summary

1. Always show loading states for async operations
2. Handle errors gracefully with user-friendly messages
3. Use optimistic updates for instant UX feedback
4. Cache blockchain data to reduce RPC calls
5. Debounce user input validation
6. Use WebSocket subscriptions for real-time updates
7. Clean up subscriptions on component unmount

# Transaction UI Patterns

Sending transactions is the core interaction in any Solana dApp. Great UX requires clear transaction flows, status tracking, and helpful feedback.

## Multi-Step Confirmation Flow

Break complex transactions into clear steps:

```typescript
enum TxStep {
  IDLE = 'idle',
  CONFIRMING = 'confirming',
  SIGNING = 'signing',
  SENDING = 'sending',
  CONFIRMING_TX = 'confirming_tx',
  SUCCESS = 'success',
  ERROR = 'error',
}

function SwapInterface() {
  const [step, setStep] = useState<TxStep>(TxStep.IDLE);
  const [signature, setSignature] = useState<string>('');

  async function handleSwap() {
    try {
      setStep(TxStep.CONFIRMING);
      // User reviews swap details

      setStep(TxStep.SIGNING);
      const { signature } = await sendTransaction(tx, connection);
      setSignature(signature);

      setStep(TxStep.SENDING);
      // Transaction sent to network

      setStep(TxStep.CONFIRMING_TX);
      await connection.confirmTransaction(signature, 'confirmed');

      setStep(TxStep.SUCCESS);
    } catch (err) {
      setStep(TxStep.ERROR);
    }
  }

  return (
    <div>
      {step === TxStep.CONFIRMING && <ReviewModal />}
      {step === TxStep.SIGNING && <WalletSigningPrompt />}
      {step === TxStep.SENDING && <SendingAnimation />}
      {step === TxStep.CONFIRMING_TX && <ConfirmingAnimation signature={signature} />}
      {step === TxStep.SUCCESS && <SuccessMessage signature={signature} />}
      {step === TxStep.ERROR && <ErrorMessage />}
    </div>
  );
}
```

## Status Indicators

Show clear visual feedback for each stage:

```typescript
function TransactionStatus({ step }: { step: TxStep }) {
  const stages = [
    { label: 'Review', step: TxStep.CONFIRMING },
    { label: 'Sign', step: TxStep.SIGNING },
    { label: 'Send', step: TxStep.SENDING },
    { label: 'Confirm', step: TxStep.CONFIRMING_TX },
  ];

  return (
    <div className="flex gap-2">
      {stages.map((stage, idx) => (
        <div key={idx} className="flex items-center">
          <div className={cn(
            "w-8 h-8 rounded-full flex items-center justify-center",
            step === stage.step && "bg-purple-600 text-white",
            idx < stages.findIndex(s => s.step === step) && "bg-green-600",
          )}>
            {idx < stages.findIndex(s => s.step === step) ? '✓' : idx + 1}
          </div>
          <span className="ml-2">{stage.label}</span>
        </div>
      ))}
    </div>
  );
}
```

## Explorer Links

Always provide links to view transactions on-chain:

```typescript
function ExplorerLink({
  signature,
  cluster = 'mainnet-beta',
}: {
  signature: string;
  cluster?: string;
}) {
  const url = `https://explorer.solana.com/tx/${signature}${cluster !== 'mainnet-beta' ? `?cluster=${cluster}` : ''}`;

  return (
    <a
      href={url}
      target="_blank"
      rel="noopener noreferrer"
      className="text-purple-600 hover:underline flex items-center gap-1"
    >
      View on Solana Explorer
      <ExternalLinkIcon className="w-4 h-4" />
    </a>
  );
}
```

## Estimated Cost Display

Show users the transaction cost before signing:

```typescript
async function estimateTransactionCost(
  transaction: Transaction,
  connection: Connection
): Promise<number> {
  const { blockhash } = await connection.getLatestBlockhash();
  transaction.recentBlockhash = blockhash;

  // Estimate fee
  const fee = await transaction.getEstimatedFee(connection);
  return fee || 5000; // Default fallback
}

function TransactionPreview({ transaction }: { transaction: Transaction }) {
  const { connection } = useConnection();
  const [fee, setFee] = useState<number | null>(null);

  useEffect(() => {
    estimateTransactionCost(transaction, connection).then(setFee);
  }, [transaction, connection]);

  return (
    <div className="bg-gray-100 p-4 rounded">
      <p className="text-sm text-gray-600">Estimated network fee</p>
      <p className="text-lg font-bold">
        {fee ? `${(fee / LAMPORTS_PER_SOL).toFixed(6)} SOL` : 'Calculating...'}
      </p>
    </div>
  );
}
```

## Retry Logic

Handle failed transactions gracefully:

```typescript
function useTransactionSender() {
  const { connection } = useConnection();
  const { sendTransaction } = useWallet();
  const [attempts, setAttempts] = useState(0);

  async function sendWithRetry(
    transaction: Transaction,
    maxRetries = 3
  ): Promise<string> {
    for (let i = 0; i < maxRetries; i++) {
      setAttempts(i + 1);

      try {
        const signature = await sendTransaction(transaction, connection);
        await connection.confirmTransaction(signature, 'confirmed');
        return signature;
      } catch (err) {
        if (i === maxRetries - 1) throw err;

        // Wait before retry (exponential backoff)
        await new Promise(resolve => setTimeout(resolve, 1000 * Math.pow(2, i)));
      }
    }

    throw new Error('Transaction failed after retries');
  }

  return { sendWithRetry, attempts };
}
```

## Transaction History

Show users their past transactions:

```typescript
function TransactionHistory() {
  const { publicKey } = useWallet();
  const { connection } = useConnection();
  const [txs, setTxs] = useState<ParsedTransactionWithMeta[]>([]);

  useEffect(() => {
    if (!publicKey) return;

    connection.getSignaturesForAddress(publicKey, { limit: 10 })
      .then(async (sigs) => {
        const txPromises = sigs.map(sig => 
          connection.getParsedTransaction(sig.signature, {
            maxSupportedTransactionVersion: 0,
          })
        );
        const txs = await Promise.all(txPromises);
        setTxs(txs.filter(tx => tx !== null));
      });
  }, [publicKey, connection]);

  return (
    <div>
      {txs.map((tx, idx) => (
        <TransactionCard key={idx} tx={tx} />
      ))}
    </div>
  );
}
```

